    for (neighbor in adj[node]) {
        if (!visited[neighbor]) {
            val newMax = dfs(neighbor, visited, adj, label, currentPath, currentMax)
            if (newMax > currentMax) {
                currentMax = newMax
            }
        }
    }

    currentPath.deleteCharAt(currentPath.length - 1)
    visited[node] = false
    return currentMax
}

private fun isPalindrome(s: String): Boolean {
    var left = 0
    var right = s.length - 1
    while (left < right) {
        if (s[left] != s[right]) {
            return false
        }
        left++
        right--
    }
    return true
}
